-- platform: 3 rows
INSERT OR IGNORE INTO platform (id, name, short_name, description, created_at, updated_at) VALUES ('be03be2d-56b3-4f20-a3d9-dd779dd06b1d', 'Bolt Action', 'bolt', 'Traditional bolt-action rifles. Most flexible platform — can be chambered in virtually any cartridge. Action length (short, long, magnum) is the main constraint.', '2026-02-28 13:37:17.316130', '2026-02-28 13:37:17.316131');
INSERT OR IGNORE INTO platform (id, name, short_name, description, created_at, updated_at) VALUES ('124ba849-3481-41fb-a26b-c588d0790b4e', 'AR-15', 'ar15', 'AR-15 pattern rifles. Limited by the AR-15 magazine well and bolt face diameter. Typically mini/short-action cartridges with max OAL ~2.260".', '2026-02-28 13:37:17.316425', '2026-02-28 13:37:17.316426');
INSERT OR IGNORE INTO platform (id, name, short_name, description, created_at, updated_at) VALUES ('11041024-ff1d-4620-a383-96f094b21614', 'AR-10', 'ar10', 'AR-10 / SR-25 / LR-308 pattern rifles. Larger magwell than AR-15. Handles .308-class cartridges. Also known as DPMS or ArmaLite pattern.', '2026-02-28 13:37:17.316573', '2026-02-28 13:37:17.316574');

-- manufacturer: 86 rows
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('a9cfb271-e05f-439a-a269-b0eef72d4f7c', 'Barnes Bullets', '["Barnes", "Barnes Bullets LLC"]', 'https://www.barnesbullets.com', NULL, '["bullet_maker"]', 'USA', 'Pioneer of monolithic copper bullets (TSX, TTSX, LRX). LRX line relevant for long-range hunting. Owned by Bullseye Acquisitions/JDH Capital (same group as Sierra and Savage), NOT Remington/Vista.', '2026-02-28 13:37:17.302860', '2026-02-28 13:37:17.302864', 'Bullseye Acquisitions / JDH Capital');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('e0a5f656-dcda-4789-9152-8e17680993d9', 'Berger Bullets', '["Berger", "Burger", "Berger Bullets Nammo"]', 'https://www.bergerbullets.com', NULL, '["bullet_maker"]', 'USA', '76% of top-200 PRS shooters use Berger bullets. Hybrid Target and VLD designs dominate competition. 109gr LRHT is the #1 6mm bullet in PRS (39% share). Owned by Nammo Group since Oct 2016 (NOT sold to JRS Enterprises — that claim is unverified).', '2026-02-28 13:37:17.302869', '2026-02-28 13:37:17.302870', 'Nammo Group (Capstone Precision Group)');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('4a9cd7c9-abba-455b-b2fa-722895763730', 'Cutting Edge Bullets', '["CEB", "Cutting Edge", "CE Bullets"]', 'https://www.cuttingedgebullets.com', NULL, '["bullet_maker"]', 'USA', '#1 bullet brand in ELR (Extreme Long Range) competitions. Monolithic solid copper/brass lathe-turned. SealTite Band technology. Founded by Dan Smitchko.', '2026-02-28 13:37:17.302875', '2026-02-28 13:37:17.302875', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('0d664870-86f7-45da-bfab-a772db35972b', 'Federal Premium', '["Federal", "Federal Ammunition", "ATK Federal", "Kinetic Group Federal"]', 'https://www.federalpremium.com', NULL, '["ammo_maker", "bullet_maker"]', 'USA', 'Gold Medal Match line is the factory ammo benchmark. Federal Gold Medal Berger loads (156 EOL, 153.5 LRHT) used by PRS competitors. As of Nov 2024, owned by Czechoslovak Group (CSG) as part of "The Kinetic Group" after Vista Outdoor split. Also owns CCI and Speer.', '2026-02-28 13:37:17.302882', '2026-02-28 13:37:17.302883', 'Czechoslovak Group (CSG) / The Kinetic Group');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('3e6572d9-0267-490c-9c7a-6899ce90830f', 'Hammer Bullets', '["Hammer", "Hammer Hunting Bullets"]', 'https://www.hammerbullets.com', NULL, '["bullet_maker"]', 'USA', 'Patented solid copper with driving band design. Reduces barrel fouling. Popular with long-range hunters. Controlled petal shedding for deep penetration. Validated to 900+ yds on elk.', '2026-02-28 13:37:17.302887', '2026-02-28 13:37:17.302887', 'H D Custom Rifles & Ammunition LLC');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('9423dd9e-cc66-4137-86fc-2de084a4dcf6', 'Hornady', '["Hornady Manufacturing", "Hornaday", "Hornady Mfg"]', 'https://www.hornady.com', NULL, '["bullet_maker", "ammo_maker"]', 'USA', 'Major bullet/ammo maker. ELD Match and A-Tip lines are precision staples. Also makes brass. Independently family-owned, based in Grand Island, NE. Founded 1949.', '2026-02-28 13:37:17.302890', '2026-02-28 13:37:17.302891', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('5147433d-5513-411c-9abf-004d01eeac62', 'Lapua', '["Nammo Lapua", "Lupua", "Lapua Oy"]', 'https://www.lapua.com', NULL, '["bullet_maker", "ammo_maker"]', 'Finland', 'Premium brass and Scenar/Scenar-L bullet line. Lapua brass is used by ~46% of top PRS shooters (with Alpha Munitions, they account for 92%). Parent company Nammo (same group as Berger, Vihtavuori, SK).', '2026-02-28 13:37:17.302894', '2026-02-28 13:37:17.302894', 'Nammo Group');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('ffab98f3-9d5f-4f3e-8a9e-add1000289a7', 'Lehigh Defense', '["Lehigh", "Lehigh Bullets"]', 'https://www.lehighdefense.com', NULL, '["bullet_maker", "ammo_maker"]', 'USA', 'Controlled Fracturing technology. More defense/LE focused but has rifle bullets. Match Solid line for precision. Based in Clarksville, TX.', '2026-02-28 13:37:17.302898', '2026-02-28 13:37:17.302899', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('bdfdd4c4-5158-4cfa-9288-c9ef3d053037', 'Norma', '["Norma Ammunition", "Norma Precision", "Norma Ammo"]', 'https://www.norma-ammunition.com', NULL, '["ammo_maker", "bullet_maker"]', 'Sweden', 'Premium ammo and brass. One of the top 4 brass brands used by PRS competitors. ~240 employees, 100+ calibers. Founded 1902. Owned by Beretta. Also makes component bullets.', '2026-02-28 13:37:17.302902', '2026-02-28 13:37:17.302902', 'Beretta Holding');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('7f66e7ca-3d7b-4847-a520-eb719b5abaf7', 'Nosler', '["Nosler Inc", "Nossler"]', 'https://www.nosler.com', NULL, '["bullet_maker", "ammo_maker", "rifle_maker"]', 'USA', 'Invented the Partition bullet. Makes loaded ammo (Trophy Grade), component bullets (AccuBond LR, RDF, Custom Competition), brass, and the Model 21 rifle. Independent, based in Bend, OR.', '2026-02-28 13:37:17.302905', '2026-02-28 13:37:17.302905', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('47a2a26a-c170-42be-9f30-3514afd47751', 'Sierra Bullets', '["Sierra", "Sierra Bullet"]', 'https://www.sierrabullets.com', NULL, '["bullet_maker"]', 'USA', 'MatchKing line is the precision standard. Sierra is NOT part of the CSG/Kinetic Group — sold by Clarus Corp to JDH Capital (Bullseye Acquisitions) in Dec 2023 for $175M. Same ownership group as Savage Arms and Barnes.', '2026-02-28 13:37:17.302908', '2026-02-28 13:37:17.302908', 'Bullseye Acquisitions / JDH Capital');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('7c877165-95d4-4166-a5fe-163ac00a6277', 'Speer', '["Speer Ammunition", "Speer Ammo"]', 'https://www.speer.com', NULL, '["bullet_maker", "ammo_maker"]', 'USA', 'Gold Dot line for duty/defense. Less relevant to precision/LR rifle market. Now owned by CSG/Kinetic Group (Nov 2024) after Vista Outdoor split.', '2026-02-28 13:37:17.302911', '2026-02-28 13:37:17.302911', 'Czechoslovak Group (CSG) / The Kinetic Group');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('8717025b-1bd6-403b-accc-7e6b626e5e1c', 'Alpha Munitions', '["Alpha", "Alpha Brass", "ADG", "Alpha Dog Gear"]', 'https://www.alphamunitions.com', NULL, '["ammo_maker"]', 'USA', 'Premium brass — with Lapua, accounts for 92% of top-200 PRS brass market. American-made in Salt Lake City, UT. Rapidly growing among competitive shooters.', '2026-02-28 13:37:17.302914', '2026-02-28 13:37:17.302914', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('193ef7db-aa37-45ac-864a-745c366c79cf', 'Black Hills Ammunition', '["Black Hills", "BHA", "BH Ammo", "Blackhills"]', 'https://www.black-hills.com', NULL, '["ammo_maker"]', 'USA', 'Premium loaded ammo favored by precision shooters. MK 262 Mod 1 military contract. 77gr TMK loads popular for AR precision. Independent, family-owned.', '2026-02-28 13:37:17.302917', '2026-02-28 13:37:17.302918', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('00475793-33a5-4a31-adc5-e11501bc6136', 'IMI Systems', '["IMI", "IMI Ammunition", "Israeli Military Industries", "IMI Defense"]', 'https://www.imisystems.com', NULL, '["ammo_maker"]', 'Israel', 'Military and commercial ammo. Razorcore line for precision. Owned by Elbit Systems since Nov 2018 (~$495M). Imported by various US distributors.', '2026-02-28 13:37:17.302921', '2026-02-28 13:37:17.302921', 'Elbit Systems');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('999a67f5-4149-4d02-b4fd-f204c1ff2c44', 'Peterson Cartridge', '["Peterson", "Peterson Brass"]', 'https://www.petersoncartridge.com', NULL, '["ammo_maker"]', 'USA', 'Match-grade American-made brass specifically for long-range shooters. Based in Pittsburgh, PA. Known for extremely consistent weight/dimensions. Family-owned.', '2026-02-28 13:37:17.302924', '2026-02-28 13:37:17.302924', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('a4fd1efd-b66d-4fd4-a55b-1fdebf09fa58', 'Prvi Partizan', '["PPU", "Privi Partizan", "Privi", "Prvi"]', 'https://www.prvipartizan.com', NULL, '["ammo_maker"]', 'Serbia', 'Affordable brass-cased ammo. Popular for practice/training. Good quality for the price. Not a precision brand but widely used for volume shooting.', '2026-02-28 13:37:17.302927', '2026-02-28 13:37:17.302927', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('dd62c1e0-f494-465f-84eb-cacd3cf61a43', 'Remington', '["Remington Arms", "Big Green", "Rem", "RemArms", "Remington 700"]', 'https://www.remington.com', NULL, '["rifle_maker", "ammo_maker"]', 'USA', 'Model 700 is the most common precision rifle action footprint (de facto standard). Post-2020 bankruptcy, firearms and ammo split. Remington Ammunition now under CSG/Kinetic Group. Rifles under RemArms (Roundhill Group).', '2026-02-28 13:37:17.302930', '2026-02-28 13:37:17.302930', 'RemArms (rifles) / CSG (ammo)');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('aee2660c-74fb-4fbe-bfb1-13cc8012d87b', 'Sellier & Bellot', '["S&B", "Sellier and Bellot", "Sellier Bellot"]', 'https://www.sellier-bellot.cz', NULL, '["ammo_maker"]', 'Czech Republic', 'One of the oldest ammo manufacturers (est. 1825). Owned by Colt CZ Group (acquired 2024 for $703M). Budget-friendly practice ammo. Not a primary precision brand but widely used for training.', '2026-02-28 13:37:17.302933', '2026-02-28 13:37:17.302933', 'Colt CZ Group SE');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('a4bc97dd-d74c-4887-b6a2-7e35982500fc', 'Starline Brass', '["Starline", "Starline Inc"]', 'https://www.starlinebrass.com', NULL, '["ammo_maker"]', 'USA', 'Nearly 50 years of brass production. Primarily handgun brass but expanding rifle offerings. Huge volume, good quality, very affordable. Independent.', '2026-02-28 13:37:17.302936', '2026-02-28 13:37:17.302936', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('1524143e-bb0b-4ad4-8976-7af58ce2ce98', 'Winchester', '["Winchester Ammunition", "Win", "Olin Winchester"]', 'https://www.winchester.com', NULL, '["ammo_maker"]', 'USA', 'Ammo manufactured by Olin Corporation. Brand name on many caliber designations (.308 Win, .270 Win, etc.). Olin/Winchester acquired AMMO Inc small-cal assets in Apr 2025. Match/precision ammo not a primary strength.', '2026-02-28 13:37:17.302939', '2026-02-28 13:37:17.302939', 'Olin Corporation');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('8ce25cf8-e5da-43de-824b-43f499c4e94f', 'Accuracy International', '["AI", "Accuracy Intl", "Accuracy Int''l"]', 'https://www.accuracyinternational.com', NULL, '["rifle_maker"]', 'United Kingdom', 'Military precision rifles (AXSR, AT-X). Used by military/LE worldwide. Premium price point. Less common in PRS (more tactical/military) but highly recognized. Founded 1978.', '2026-02-28 13:37:17.302942', '2026-02-28 13:37:17.302942', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('dfca864d-4575-4cb8-8ea8-eabb0bd2b341', 'Aero Precision', '["Aero", "Aero Precision USA", "AP"]', 'https://www.aeroprecisionusa.com', NULL, '["rifle_maker"]', 'USA', 'Major OEM supplier — makes receivers for many brands. M5 (.308/AR-10) and AR-15 lines are go-to for builders. Solus bolt-action line gaining traction in precision. Based in Tacoma, WA.', '2026-02-28 13:37:17.302945', '2026-02-28 13:37:17.302945', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('e069a5c2-58fc-4708-b79b-4b7a9207f8ae', 'Bergara', '["Bergara Rifles", "Bergara USA", "Bargara"]', 'https://www.bergara.online/us', NULL, '["rifle_maker"]', 'Spain', 'B-14 HMR is a benchmark for precision-for-the-money. Premier Competition Rifle (partnered with MPA chassis) gaining PRS traction. Known for hammer-forged barrel quality. Spanish barrel-making heritage.', '2026-02-28 13:37:17.302948', '2026-02-28 13:37:17.302948', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('b4d7dce7-6d0f-438f-8e10-f6ac2f5d9817', 'Bravo Company', '["BCM", "Bravo Company Manufacturing", "Bravo Company MFG"]', 'https://www.bravocompanymfg.com', NULL, '["rifle_maker"]', 'USA', 'Best value in duty-grade AR segment. Not competition-focused but hugely popular among serious shooters. RECCE-16 and MK2 lines.', '2026-02-28 13:37:17.302951', '2026-02-28 13:37:17.302951', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('70dbafde-1f71-4676-a499-3307c31df9cd', 'Browning', '["Browning Arms", "Browning Firearms"]', 'https://www.browning.com', NULL, '["rifle_maker"]', 'USA', 'X-Bolt line is popular for hunting. X-Bolt Max Long Range is their precision-adjacent offering. Brand owned by FN Herstal (Belgium). Very large user base among hunters.', '2026-02-28 13:37:17.302954', '2026-02-28 13:37:17.302954', 'FN Herstal / Herstal Group');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('7ab96a42-b9f9-45dc-98ea-06852287adc7', 'CZ (Česká zbrojovka)', '["CZ", "CZ-USA", "Ceska Zbrojovka", "CZUB", "CZ Firearms"]', 'https://www.cz-usa.com', NULL, '["rifle_maker"]', 'Czech Republic', 'CZ 600 series with interchangeable barrels and sub-MOA guarantee. Also owns Colt. CZ 457 rimfire is widely used for trainer rifles. Cold hammer-forged barrels.', '2026-02-28 13:37:17.302957', '2026-02-28 13:37:17.302957', 'Colt CZ Group SE');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('851b102c-99e3-42d9-8aaa-c71025e5eed4', 'Cadex Defence', '["Cadex", "Cadex Defense"]', 'https://www.cadexdefence.com', NULL, '["rifle_maker", "chassis_maker"]', 'Canada', 'Precision sniper rifles and chassis systems. CDX-MC Kraken multi-caliber rifle. Field Competition chassis used in PRS. Recoil management systems. Based in QC, Canada. Since 1994.', '2026-02-28 13:37:17.302960', '2026-02-28 13:37:17.302960', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('357a10bf-3ac3-423c-92aa-574e18050258', 'Christensen Arms', '["Christensen", "CA", "Christenson Arms"]', 'https://www.christensenarms.com', NULL, '["rifle_maker"]', 'USA', 'Pioneer of carbon fiber barrel technology. Lightweight hunting and long-range precision rifles. MPR (Modern Precision Rifle) is their PRS-relevant model. 30th anniversary in 2025. Gunnison, UT.', '2026-02-28 13:37:17.302963', '2026-02-28 13:37:17.302963', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('edfbce34-b77b-4ef2-a1ec-5be862b18b3a', 'Curtis Custom', '["Curtis", "Curtis Actions"]', 'https://www.curtiscustom.com', NULL, '["parts_maker", "rifle_maker"]', 'USA', 'Custom actions (Valor, Axiom, Scout) and bespoke rifles. Premium quality. Texas-based. Requires FFL for shipping.', '2026-02-28 13:37:17.302966', '2026-02-28 13:37:17.302966', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('ce3c8418-f08f-44fd-b556-7fef982ef570', 'Daniel Defense', '["DD", "Dan Def", "Daniel Defense Inc"]', 'https://www.danieldefense.com', NULL, '["rifle_maker"]', 'USA', 'Premium AR-15 and AR-10 maker. DDM4 series is benchmark for hard-use precision ARs. Cold hammer-forged barrels, most components in-house. Delta 5 bolt-action is their precision entry.', '2026-02-28 13:37:17.302969', '2026-02-28 13:37:17.302969', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('24e66dfd-1cf5-4af4-98d2-b9fdc2d6b04e', 'Desert Tech', '["DT", "DesertTech", "Desert Tech SRS"]', 'https://www.deserttech.com', NULL, '["rifle_maker"]', 'USA', 'Bullpup precision rifles (SRS-A2, HTI). Compact form factor for precision shooting. MDR/MDRx lines discontinued 2024. Based in West Valley City, UT.', '2026-02-28 13:37:17.302972', '2026-02-28 13:37:17.302972', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('7a2c035e-462c-4618-8d48-519473f625b3', 'GA Precision', '["GAP", "GA Prec", "George Gardner"]', 'https://www.gaprecision.net', NULL, '["rifle_maker"]', 'USA', 'Custom precision rifle builds by George Gardner. Consistently top-5 in PRS since inception (2012). FBI SWAT trusted. GAP is shorthand for "good enough for PRS." Kansas City area.', '2026-02-28 13:37:17.302975', '2026-02-28 13:37:17.302975', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('1bdcb0cf-fa97-4aaf-9aa1-abbaaa688042', 'Geissele Automatics', '["Geissele", "Geisele", "Giesele", "Geissele Automatics LLC"]', 'https://www.geissele.com', NULL, '["rifle_maker", "parts_maker"]', 'USA', 'Known primarily for triggers (SSA-E is the gold standard AR trigger). Super Duty rifle is a benchmark premium AR. Most precision AR shooters have a Geissele trigger.', '2026-02-28 13:37:17.302978', '2026-02-28 13:37:17.302978', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('35562c9d-48e8-4586-a217-02c60c317ad2', 'Howa', '["Howa Machinery", "Howa 1500", "Howa USA"]', 'https://www.howausa.com', NULL, '["rifle_maker"]', 'Japan', 'Imported/distributed by Legacy Sports International in the US. Howa 1500 action is basis for many budget precision builds. Mini action popular in 6.5 Grendel builds.', '2026-02-28 13:37:17.302981', '2026-02-28 13:37:17.302981', 'Howa Machinery Ltd (Japan)');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('54944209-93aa-4622-b0f5-9e980eb2e1f4', 'JP Enterprises', '["JP", "JPE", "JP Rifles"]', 'https://www.jprifles.com', NULL, '["rifle_maker"]', 'USA', 'Purpose-built competition gas guns. LRP-07 and CTR-02 are staples in PRS Gas Gun division. Known for tuned gas systems and match barrels.', '2026-02-28 13:37:17.302984', '2026-02-28 13:37:17.302984', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('840b38c3-95d1-4ee3-bf58-a640019f474c', 'Knight''s Armament', '["KAC", "Knight''s", "Knights Armament", "Knight''s Armament Company"]', 'https://www.knightarmco.com', NULL, '["rifle_maker"]', 'USA', 'SR-25 is the US military semi-auto precision platform (M110 SASS). SR-15 for 5.56. Extremely high-end, limited availability, cult following. Founded by Reed Knight.', '2026-02-28 13:37:17.302987', '2026-02-28 13:37:17.302987', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('65564d9a-5cd2-47f1-a5b8-5ce6e8760ef8', 'LWRC International', '["LWRC", "LWRCI"]', 'https://www.lwrci.com', NULL, '["rifle_maker"]', 'USA', 'Short-stroke piston ARs. REPR in .308 is a legitimate precision platform. Niche but respected among AR shooters.', '2026-02-28 13:37:17.302990', '2026-02-28 13:37:17.302990', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('bbe139fc-2c97-42f8-8e7e-8fffce68e8dc', 'LaRue Tactical', '["LaRue", "Larue", "La Rue"]', 'https://www.larue.com', NULL, '["rifle_maker"]', 'USA', 'OBR (Optimized Battle Rifle) and PredatAR are legendary for accuracy. Often described as the most accurate factory AR. Cult following. MBT-2S trigger is a massive value play.', '2026-02-28 13:37:17.302993', '2026-02-28 13:37:17.302993', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('f790e019-7145-41dc-96ce-239023287f2d', 'Lewis Machine & Tool', '["LMT", "Lewis Machine", "LMT Defense"]', 'https://www.lmtdefense.com', NULL, '["rifle_maker"]', 'USA', 'Monolithic upper receiver design (MRP). .308 MWS is a respected precision platform. Quick-change barrel system. Military contracts worldwide (NZ, Estonia, UK).', '2026-02-28 13:37:17.302996', '2026-02-28 13:37:17.302996', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('6235e9b7-9c46-4472-9bd3-73ad80fc9290', 'Masterpiece Arms', '["MPA", "Masterpiece Arms Inc", "Master Piece Arms"]', 'https://www.masterpiecearms.com', NULL, '["rifle_maker", "chassis_maker"]', 'USA', 'Dominant PRS rifle/chassis brand. BA Comp chassis used by 29% of top-200 PRS shooters and 44% of top-25. MPA + Foundation + MDT = 79% of top PRS chassis market. Named official PRS chassis 5 consecutive years. Based in Comer, GA.', '2026-02-28 13:37:17.302999', '2026-02-28 13:37:17.302999', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('32d7b1b5-fdd4-4607-a662-b6387863c580', 'Mossberg', '["O.F. Mossberg", "Mossberg & Sons"]', 'https://www.mossberg.com', NULL, '["rifle_maker"]', 'USA', 'Patriot line is a budget bolt-action option. MVP platform in 5.56/.308. Very large user base due to low pricing. Less precision-focused but many owners.', '2026-02-28 13:37:17.303002', '2026-02-28 13:37:17.303002', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('3331950e-a09a-44b4-9b23-d04739a9f5ae', 'Palmetto State Armory', '["PSA", "Palmetto", "Palmetto State"]', 'https://www.palmettostatearmory.com', NULL, '["rifle_maker", "ammo_maker"]', 'USA', 'Massive volume, aggressive pricing. Gen3 PA-10 in 6.5 CM is surprisingly capable. Also owns DAGR Arms and other brands. Sheer volume means many users will own one.', '2026-02-28 13:37:17.303005', '2026-02-28 13:37:17.303005', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('14fe0211-8d9d-483e-aa6d-8c55dd635341', 'Proof Research', '["Proof", "PROOF", "Proof Barrels"]', 'https://www.proofresearch.com', NULL, '["rifle_maker", "parts_maker"]', 'USA', 'Carbon fiber barrel technology (aerospace-grade). 12% of top PRS shooters use Proof barrels (2nd most popular after Bartlein). Conviction rifle system. NW Montana near Glacier.', '2026-02-28 13:37:17.303008', '2026-02-28 13:37:17.303008', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('4f28240e-19d1-4bad-bd23-2b2e102615c6', 'Ruger', '["Sturm Ruger", "Sturm Ruger & Co", "Ruger Firearms", "Rugar"]', 'https://www.ruger.com', NULL, '["rifle_maker"]', 'USA', 'Ruger Precision Rifle (RPR) was a game-changer — brought sub-$1500 chassis rifles to market. Huge install base among newer precision shooters. Also makes American Predator and Hawkeye lines.', '2026-02-28 13:37:17.303011', '2026-02-28 13:37:17.303011', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('0a2aae98-7afd-4266-9c1b-93dcd7550cb2', 'Sako', '["Sako Rifles", "Sako Finland", "Sakko"]', 'https://www.sako.global', NULL, '["rifle_maker"]', 'Finland', 'Finnish precision bolt-action rifles. Makes Tikka rifles at their Riihimäki factory. TRG series is their precision/tactical line. Premium price point. Owned by Beretta since 2000.', '2026-02-28 13:37:17.303014', '2026-02-28 13:37:17.303014', 'Beretta Holding');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('234c3e29-73ba-478d-8895-75e2654fb03d', 'Savage Arms', '["Savage", "Savage Firearms", "Savage 110"]', 'https://www.savagearms.com', NULL, '["rifle_maker"]', 'USA', 'Model 110 platform is long-lived and accurate. AccuTrigger user-adjustable trigger was innovative. Impulse straight-pull gaining interest. Owned by JDH Capital (same group as Sierra, Barnes).', '2026-02-28 13:37:17.303017', '2026-02-28 13:37:17.303017', 'Bullseye Acquisitions / JDH Capital');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('c5cdae2d-d66e-459c-ad7c-340e685b92f3', 'Seekins Precision', '["Seekins", "Seekins SP"]', 'https://www.seekinsprecision.com', NULL, '["rifle_maker"]', 'USA', 'Havak line well-regarded for factory precision bolt actions. SP10 for gas guns. HIT (Havak In Training) is an accessible entry. Based in Lewiston, ID.', '2026-02-28 13:37:17.303021', '2026-02-28 13:37:17.303021', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('3ffe339d-7a77-449a-b72f-d3cb49484232', 'Sig Sauer', '["Sig", "SIG SAUER", "Sig Sauer Inc", "SIG"]', 'https://www.sigsauer.com', NULL, '["optic_maker", "rifle_maker"]', 'USA', 'Tango6T adopted by US Army (SDMR). Cross bolt-action rifle for hunting/precision. KILO rangefinders widely used. Large defense contractor. Based in Newington, NH.', '2026-02-28 13:37:17.303024', '2026-02-28 13:37:17.303025', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('f3aacc35-3c2c-483d-8cfa-306374569a68', 'Tikka', '["Tikka Rifles", "Tikka T3x", "Tikka by Sako"]', 'https://www.tikka.fi', NULL, '["rifle_maker"]', 'Finland', 'Made by Sako (Beretta Group). T3x TAC A1 is popular precision chassis rifle. T3x CTR and Lite also widely used. Exceptional factory trigger. One of the most recommended entry precision rifles.', '2026-02-28 13:37:17.303027', '2026-02-28 13:37:17.303028', 'Beretta Group (via Sako)');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('e95d0928-0cfe-44b0-b9fe-1322d915ff70', 'Weatherby', '["Weatherby Inc", "Wby", "Weatherby Vanguard"]', 'https://www.weatherby.com', NULL, '["rifle_maker", "ammo_maker"]', 'USA', 'Known for proprietary magnum cartridges (.300 Wby Mag, .30-378 Wby). Mark V and Vanguard rifles. Vanguard is a rebranded Howa 1500. Recently moved HQ to Sheridan, WY.', '2026-02-28 13:37:17.303030', '2026-02-28 13:37:17.303031', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('58137c72-e12b-42e6-9022-64b3a8aacbf6', 'Area 419', '["Area419", "A419", "Area 419 LLC"]', 'https://www.area419.com', NULL, '["parts_maker", "chassis_maker"]', 'USA', 'Hellfire muzzle brake is PRS standard. ARCA rails, scope mounts, and accessories. XYLO chassis (American Rifle Co). Premium competition components. Major PRS retailer.', '2026-02-28 13:37:17.303033', '2026-02-28 13:37:17.303033', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('685f559f-9c04-4fa0-b572-744b3d883e6a', 'Foundation Stocks', '["Foundation", "Foundation Rifle Stocks"]', 'https://www.foundationstocks.com', NULL, '["chassis_maker"]', 'USA', 'Top-3 PRS stock brand (with MPA and MDT = 79% of top chassis market). Genesis and Centurion models. Precision composite stocks machined from solid blocks.', '2026-02-28 13:37:17.303036', '2026-02-28 13:37:17.303036', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('5e7097d9-806c-4481-aceb-28da100f9714', 'Grayboe', '["Grayboe Stocks"]', 'https://www.grayboe.com', NULL, '["chassis_maker"]', 'USA', 'Fiberglass stocks (Ridgeback, Renegade). Affordable composite option. American-made.', '2026-02-28 13:37:17.303039', '2026-02-28 13:37:17.303039', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('39906052-aed9-4bcf-a0e6-cd5d358b3b86', 'KRG (Kinetic Research Group)', '["KRG", "Kinetic Research", "KRG Whiskey"]', 'https://www.kineticresearchgroup.com', NULL, '["chassis_maker"]', 'USA', 'Whiskey-3 Gen 7 and Bravo chassis are PRS staples. W3 is a top-5 chassis in PRS. AICS magazine compatible. High quality aluminum construction.', '2026-02-28 13:37:17.303042', '2026-02-28 13:37:17.303042', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('09a6eca4-228b-489e-8a0d-5406b4654c65', 'MDT (Modular Driven Technologies)', '["MDT", "Modular Driven", "MDT Chassis", "Oryx by MDT"]', 'https://www.mdttac.com', NULL, '["chassis_maker"]', 'Canada', 'Top-3 PRS chassis brand (with MPA and Foundation = 79% of top PRS). ACC, ACC Elite, LSS-XL, and HNT26 lines. Also makes Oryx budget chassis. Based in Chilliwack, BC.', '2026-02-28 13:37:17.303045', '2026-02-28 13:37:17.303046', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('dde8a346-5b1d-45c7-941e-4465840aee7c', 'Manners Composite Stocks', '["Manners", "Manners Stocks", "MCS"]', 'https://www.mannersstocks.com', NULL, '["chassis_maker"]', 'USA', 'Aerospace-grade carbon fiber stocks. PRS Series 2023 official stock sponsor. EH1 and TCS models popular in competition. Lifetime warranty.', '2026-02-28 13:37:17.303048', '2026-02-28 13:37:17.303049', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('4ab1d80e-3226-4d28-b99f-cdfb045695dd', 'McMillan', '["McMillan Stocks", "McMillian", "McMillon", "McMillan USA"]', 'https://www.mcmillanusa.com', NULL, '["chassis_maker"]', 'USA', 'Iconic A5 and A4 stocks. Handcrafted fiberglass/carbon fiber since 1974. Heritage PRS brand, less dominant now but still respected. Founded by Gale McMillan.', '2026-02-28 13:37:17.303051', '2026-02-28 13:37:17.303052', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('790e8b4c-0503-45aa-aebb-0ed94014455d', 'XLR Industries', '["XLR", "XLR Chassis"]', 'https://www.xlrindustries.com', NULL, '["chassis_maker"]', 'USA', 'American-made 6061 billet aluminum chassis. Element 4.0 and ENVY Pro. Element 4.0 Magnesium under 2 lbs. Established 2010.', '2026-02-28 13:37:17.303054', '2026-02-28 13:37:17.303055', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('09827820-3041-46e2-bbd3-6b7809200725', 'Arken Optics', '["Arken", "Arken USA"]', 'https://www.arkenopticsusa.com', NULL, '["optic_maker"]', 'USA', 'Budget FFP scopes gaining popularity. EP5 5-25x is strong PRS entry-level value. Japanese glass, Chinese assembly. Texas-based brand.', '2026-02-28 13:37:17.303057', '2026-02-28 13:37:17.303058', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('a3700b9f-04b2-40b8-b1bb-5bbf3d354aa2', 'Athlon Optics', '["Athlon", "Athlon Optics USA"]', 'https://www.athlonoptics.com', NULL, '["optic_maker"]', 'USA', 'Cronus BTR (Japan-made) is their premium precision scope. Other lines from China. Strong value proposition. Lifetime warranty. Founded 2014.', '2026-02-28 13:37:17.303060', '2026-02-28 13:37:17.303061', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('58c0a0a3-2872-4480-8ad4-6d09662c50f8', 'Bushnell', '["Bushnell Elite", "Bushnell Tactical", "Bushnell Optics"]', 'https://www.bushnell.com', NULL, '["optic_maker"]', 'USA', 'Elite Tactical line (XRS3, DMR3) relevant for precision. Owned by Vista Outdoor/Revelyst. Match Pro budget FFP scope is a strong value play.', '2026-02-28 13:37:17.303063', '2026-02-28 13:37:17.303064', 'Revelyst (formerly Vista Outdoor)');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('84f79a61-32c0-414e-890d-bb0e2512f4f0', 'Element Optics', '["Element", "Element Optics USA"]', 'https://www.element-optics.com', NULL, '["optic_maker"]', 'USA', 'Budget-friendly premium scopes. Helix and Titan lines. Founded by Fredrik Axelsson (FX Airguns). Manufacturing in Sweden (Mariestad) and design in Utah. Growing fast.', '2026-02-28 13:37:17.303066', '2026-02-28 13:37:17.303066', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('4e8df3f6-7d6d-4b32-bca9-c95ee8221116', 'Kahles', '["Kahles Optics"]', 'https://www.kahles.at', NULL, '["optic_maker"]', 'Austria', 'Oldest riflescope manufacturer (est. 1898). K525i is highly regarded in PRS. Owned by Swarovski Optik since 1974. Austrian-made in Guntramsdorf.', '2026-02-28 13:37:17.303069', '2026-02-28 13:37:17.303069', 'Swarovski Optik / Swarovski Group');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('6b4a9d31-91c0-49aa-9809-4ed60cdc880c', 'Leupold', '["Leupold & Stevens", "Leopold", "Leupold Optics"]', 'https://www.leupold.com', NULL, '["optic_maker"]', 'USA', 'Mark 5HD is the precision line. 19% of top PRS shooters (most popular brand by share, though declining from 22%). Long heritage in American optics. Made in Beaverton, OR.', '2026-02-28 13:37:17.303072', '2026-02-28 13:37:17.303072', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('b0a102ab-b793-45c2-8d54-ab1e4b0b63f4', 'March Optics', '["March", "March Scopes", "DEON"]', 'https://www.marchscopes.com', NULL, '["optic_maker"]', 'Japan', 'Hand-built in Japan by DEON Optical Design. 30+ years optical design. 150+ parts all Japanese-made. 20 quality inspections per scope. Popular in F-class and benchrest.', '2026-02-28 13:37:17.303075', '2026-02-28 13:37:17.303075', 'DEON Optical Design Corporation');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('54a4ad32-6e2a-41ea-8f88-d57d9adf4836', 'Maven', '["Maven Optics", "Maven Built"]', 'https://www.mavenbuilt.com', NULL, '["optic_maker"]', 'USA', 'Direct-to-consumer model, Japanese glass. RS.4 5-30x is their precision rifle scope. Custom builder (color/engraving options). Based in Lander, WY.', '2026-02-28 13:37:17.303078', '2026-02-28 13:37:17.303078', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('c1089f9c-70ab-4032-8e40-2be3da4ac3dc', 'Nightforce Optics', '["Nightforce", "NF", "Night Force"]', 'https://www.nightforceoptics.com', NULL, '["optic_maker"]', 'USA', 'ATACR 7-35x56 F1 is the fan favorite — all top-50 PRS shooters using NF run this model. 13% of top PRS shooters. Only brand in top-5 PRS optics for 10 consecutive years. Parent: Lightforce (Australia).', '2026-02-28 13:37:17.303081', '2026-02-28 13:37:17.303081', 'Lightforce Performance Lighting (Australia)');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('3bb2dee0-af97-412f-82fd-e9933a3d7e27', 'Revic', '["Revic Optics", "Revic PMR"]', 'https://www.revicoptics.com', NULL, '["optic_maker"]', 'USA', 'Smart scopes with integrated ballistic engines. Acura RS25i and Radikl RS25b. Sister company to Gunwerks. Interesting tech for app integration.', '2026-02-28 13:37:17.303084', '2026-02-28 13:37:17.303084', 'Gunwerks (related)');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('a4590691-212e-4122-84ec-edc3b80753b5', 'Schmidt & Bender', '["S&B Optics", "Schmidt Bender", "Schmidt and Bender", "Schmidt und Bender"]', 'https://www.schmidtundbender.de/en', NULL, '["optic_maker"]', 'Germany', 'Ultra-premium German optics for military/LE/hunting. PM II series is military precision standard. Family-owned since 1957. In-house production.', '2026-02-28 13:37:17.303087', '2026-02-28 13:37:17.303087', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('ce8f316d-6923-43da-a26d-46f5df86acf7', 'Steiner', '["Steiner Optics", "Steiner Germany"]', 'https://www.steiner-optics.com', NULL, '["optic_maker"]', 'Germany', 'Military and hunting optics. T6Xi tactical line relevant for precision. German technology, Beretta Group owned since 2008. M8Xi is their precision competition entry.', '2026-02-28 13:37:17.303090', '2026-02-28 13:37:17.303090', 'Beretta Holding');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('31ebb9de-4429-4f57-83e8-7d9d5d8df25a', 'Swarovski Optik', '["Swarovski", "Swarovski Optics", "Swaro"]', 'https://www.swarovskioptik.com', NULL, '["optic_maker"]', 'Austria', 'Ultra-premium hunting optics. dS and X5(i) lines. Less common in PRS competition but gold standard for hunting glass. Owns Kahles brand. Made in Absam, Austria since 1949.', '2026-02-28 13:37:17.303093', '2026-02-28 13:37:17.303093', 'Swarovski Group');
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('03f44348-062b-45f6-aef3-3fc6997ef50d', 'Tangent Theta', '["TT", "Tangent Theta Inc", "TangentTheta"]', 'https://www.tangenttheta.com', NULL, '["optic_maker"]', 'Canada', '17% of top PRS shooters (surging — grew from 4% to 20% in ~5 years). Tool-less Re-Zero feature. No manufacturer sponsorships — shooters choose freely. German glass. Made in Halifax, NS.', '2026-02-28 13:37:17.303096', '2026-02-28 13:37:17.303096', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('75fa8f1f-4ecc-4bab-bde1-c5810e191dea', 'US Optics', '["USO", "US Optics Inc"]', 'https://www.usoptics.com', NULL, '["optic_maker"]', 'USA', 'Hand-assembled custom riflescopes. LPVO pioneers. Foundation series (Buy American Act compliant). Since 1991, Rutherford College, NC.', '2026-02-28 13:37:17.303099', '2026-02-28 13:37:17.303099', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('3f2870a9-7f91-4573-afb4-54a7cbbf2b5c', 'Vortex Optics', '["Vortex", "Vortex Optics Inc", "Vortx"]', 'https://www.vortexoptics.com', NULL, '["optic_maker"]', 'USA', 'Dominant precision optics brand by volume. Viper PST Gen II is PRS entry-level standard. Razor HD Gen III is competition-grade. Unconditional lifetime VIP warranty. Based in Barneveld, WI.', '2026-02-28 13:37:17.303102', '2026-02-28 13:37:17.303102', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('46c82367-e324-42d8-8152-fc05583ca7a2', 'Zero Compromise Optics', '["ZCO", "Zero Compromise", "ZC Optics"]', 'https://www.zcompoptic.com', NULL, '["optic_maker"]', 'Austria', 'Ultra-premium optics. ZC527 is considered among the best precision scopes available. Small batch. Design/testing in Orofino, ID; manufacturing in Austria. Founded 2018.', '2026-02-28 13:37:17.303105', '2026-02-28 13:37:17.303105', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('bb964b0b-a440-4a5f-9170-5f13c72b3213', 'Bartlein Barrels', '["Bartlein", "Bartlien"]', 'https://www.bartleinbarrels.com', NULL, '["parts_maker"]', 'USA', '49% of top PRS shooters use Bartlein barrels — more than the next 10 brands combined. Cut-rifled, single-point, 5R rifling options. The undisputed dominant PRS barrel maker.', '2026-02-28 13:37:17.303108', '2026-02-28 13:37:17.303108', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('2bbd113d-5f7c-490c-9e2a-a849ead301c1', 'Criterion Barrels', '["Criterion", "Criterion Arms"]', 'https://www.criterionbarrels.com', NULL, '["parts_maker"]', 'USA', 'AR-platform and bolt-action barrels. CORE series for bolt guns. Hybrid profile is popular for precision AR builds. Button-rifled. Good value.', '2026-02-28 13:37:17.303110', '2026-02-28 13:37:17.303111', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('75f5f3b1-578f-40ee-85f8-482aca42b648', 'Defiance Machine', '["Defiance", "Defiance Actions"]', 'https://www.defiancemachine.com', NULL, '["parts_maker"]', 'USA', 'Custom bolt-action receivers (actions). Tenacity, Deviant, Rebel, Ruckus series. Widely used by PRS gunsmiths for custom builds. Columbia Falls, MT.', '2026-02-28 13:37:17.303113', '2026-02-28 13:37:17.303114', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('39dff045-ec0f-4d76-a3a5-6e6c5fea1511', 'Impact Precision', '["Impact", "Impact 737", "IP"]', 'https://www.impactprecision.com', NULL, '["parts_maker"]', 'USA', '737R action used by 57% of top-ranked PRS shooters — 3x more than any other brand. $1,470 MSRP (lowest among top actions). Dominant in PRS competition.', '2026-02-28 13:37:17.303116', '2026-02-28 13:37:17.303117', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('4b425f48-35cb-425f-9c1a-77d87db355d6', 'Timney Triggers', '["Timney", "Timney Mfg"]', 'https://www.timneytriggers.com', NULL, '["parts_maker"]', 'USA', 'Precision aftermarket triggers for 75+ years. CNC machined, hand-tested. Rem 700, Ruger, Savage, AR platforms. Phoenix, AZ. Founded 1946.', '2026-02-28 13:37:17.303119', '2026-02-28 13:37:17.303119', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('c4153391-be8b-4c48-a9cb-2b7d18aa210d', 'TriggerTech', '["Trigger Tech", "TriggerTech Inc"]', 'https://www.triggertech.com', NULL, '["parts_maker"]', 'Canada', 'Zero Creep Technology triggers. Rem 700, Tikka, and AR platforms. Acquired Hawkins Precision (2025), expanding product portfolio. Toronto-based.', '2026-02-28 13:37:17.303122', '2026-02-28 13:37:17.303122', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('c2d462cb-2ed8-4718-96c1-7be790f55b21', 'Zermatt Arms', '["Bighorn Arms", "Bighorn", "Bighorn Origin", "Zermatt"]', 'https://www.zermattarms.com', NULL, '["parts_maker"]', 'USA', 'Bighorn Origin action — Rem 700 footprint with Savage barrel compatibility. Popular for budget precision builds. Acquired Bighorn Arms in 2015. Bennett, NE.', '2026-02-28 13:37:17.303125', '2026-02-28 13:37:17.303125', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('c96628a4-837c-4c36-9d06-b42c972733c1', 'Applied Ballistics', '["AB", "Applied Ballistics LLC", "AB Ballistics"]', 'https://www.appliedballisticsllc.com', NULL, '["data_provider"]', 'USA', 'Bryan Litz. Doppler-measured BC data and custom drag models. Gold standard for BC values. Integrated into Kestrel meters, many ballistic apps. Mobile lab with doppler radar in west-central MI.', '2026-02-28 13:37:17.303128', '2026-02-28 13:37:17.303128', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('598b3d7f-42b2-48e4-9ba4-964fb9fe95d9', 'Garmin', '["Garmin Xero", "Garmin Ltd"]', 'https://www.garmin.com', NULL, '["data_provider"]', 'USA', 'Xero L60i laser rangefinder (7,000m range, ±0.25m accuracy) with Applied Ballistics integration. Xero X1i crossbow scope. Not a core precision brand but Xero is widely used.', '2026-02-28 13:37:17.303131', '2026-02-28 13:37:17.303131', NULL);
INSERT OR IGNORE INTO manufacturer (id, name, alt_names, website_url, logo_url, type_tags, country, notes, created_at, updated_at, parent_company) VALUES ('a7a018c2-d42e-447f-8470-1dbe96cc4317', 'Kestrel Ballistics', '["Kestrel", "Kestrel Meters", "Kestrel 5700"]', 'https://www.kestrelballistics.com', NULL, '["data_provider"]', 'USA', 'Weather meters with Applied Ballistics integration. Kestrel 5700 Elite is THE standard tool for precision shooters — measures temp, pressure, humidity, wind. MIL-STD-810G rated.', '2026-02-28 13:37:17.303134', '2026-02-28 13:37:17.303134', NULL);

