INSERT OR IGNORE INTO chamber (id, name, alt_names, notes, source, created_at, updated_at) VALUES ('04f585a9-6be4-4d12-ab5b-e652ae73bf78', '.223 Remington', 'null', 'Commercial .223 chamber. Accepts .223 Rem ONLY — do not fire 5.56 NATO.', 'SAAMI spec', '2026-02-28 13:37:17.314147', '2026-02-28 13:37:17.314148');
INSERT OR IGNORE INTO chamber (id, name, alt_names, notes, source, created_at, updated_at) VALUES ('79a9b47b-77b4-480e-a100-469fabae1736', '5.56 NATO', '["5.56x45mm NATO"]', 'Military 5.56 chamber with longer throat / leade. Safe to fire both 5.56 and .223 Rem.', 'NATO STANAG', '2026-02-28 13:37:17.314472', '2026-02-28 13:37:17.314473');
INSERT OR IGNORE INTO chamber (id, name, alt_names, notes, source, created_at, updated_at) VALUES ('c46bf156-55c9-4909-aecd-e21c22bfacb7', '.223 Wylde', 'null', 'Hybrid chamber designed to safely fire both .223 Rem and 5.56 NATO while maintaining .223 Rem accuracy. No corresponding cartridge exists — this is a chamber-only specification. The most popular AR-15 chamber for precision use.', 'Industry standard (Bill Wylde design)', '2026-02-28 13:37:17.314712', '2026-02-28 13:37:17.314713');
INSERT OR IGNORE INTO chamber (id, name, alt_names, notes, source, created_at, updated_at) VALUES ('b64d3470-7b67-4374-8874-d80d827a667b', '.308 Winchester', 'null', 'Commercial .308 Win chamber. Universally considered safe to fire 7.62x51 NATO (lower pressure) in modern rifles. Every major firearms reference treats these as interchangeable.', 'SAAMI spec', '2026-02-28 13:37:17.315022', '2026-02-28 13:37:17.315023');
INSERT OR IGNORE INTO chamber (id, name, alt_names, notes, source, created_at, updated_at) VALUES ('f802df1c-3124-4892-9791-f39fc686cac1', '7.62x51mm NATO', '["7.62 NATO"]', 'Military 7.62 chamber. Accepts both 7.62x51 and .308 Win in modern rifles.', 'NATO STANAG', '2026-02-28 13:37:17.315272', '2026-02-28 13:37:17.315273');
